firmware_template.source:
#include "dumbdisplay_camera.h"
#include <WiFi.h>
#include <esp_camera.h>
#include "dumbdisplay.h"
#include "wifidumbdisplay.h"

static DDWiFiServerIO* ddio = nullptr;
static DumbDisplay* dd = nullptr;
static GraphicalDDLayer* camLayer = nullptr;

void dd_camera_setup(const char* ssid, const char* password) {
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  ddio = new DDWiFiServerIO(nullptr, nullptr, 10201);
  dd = new DumbDisplay(ddio);
  camLayer = dd->createGraphicalLayer(320, 240);
  camera_config_t cfg;
  memset(&cfg, 0, sizeof(cfg));
  cfg.pin_d0 = 11; cfg.pin_d1 = 9; cfg.pin_d2 = 8; cfg.pin_d3 = 10;
  cfg.pin_d4 = 12; cfg.pin_d5 = 18; cfg.pin_d6 = 17; cfg.pin_d7 = 16;
  cfg.pin_xclk = 15; cfg.pin_pclk = 13; cfg.pin_vsync = 6; cfg.pin_href = 7;
  cfg.pin_sccb_sda = 4; cfg.pin_sccb_scl = 5;
  cfg.xclk_freq_hz = 20000000;
  cfg.pixel_format = PIXFORMAT_JPEG;
  cfg.frame_size = FRAMESIZE_QVGA;
  cfg.jpeg_quality = 12;
  cfg.fb_count = 2;
  esp_camera_init(&cfg);
  Serial.println("[dd_cam] Camera + DumbDisplay ready");
}

void dd_camera_loop() {
  camera_fb_t* fb = esp_camera_fb_get();
  if (fb) {
    camLayer->drawImageFileFit("camera.jpg");
    esp_camera_fb_return(fb);
  }
  delay(100);
}

void dd_camera_set_resolution(int width, int height) {
  sensor_t* s = esp_camera_sensor_get();
  if (s) {
    if (width <= 160) s->set_framesize(s, FRAMESIZE_QQVGA);
    else if (width <= 320) s->set_framesize(s, FRAMESIZE_QVGA);
    else s->set_framesize(s, FRAMESIZE_VGA);
  }
}
